from __future__ import annotations
from dataclasses import dataclass, field
from typing import Optional

@dataclass
class ThoughtNode:
    node_id: int
    content: str
    parents: list[int] = field(default_factory=list)  # IDs of parent nodes
    score: float = 0.0
    is_aggregated: bool = False  # True if created via Aggregate op

class ThoughtGraph:
    def __init__(self):
        self._nodes: dict[int, ThoughtNode] = {}
        self._next_id = 0

    def add_node(self, content: str, parents: list[int] = None, score: float = 0.0,
                 is_aggregated: bool = False) -> int:
        nid = self._next_id
        self._next_id += 1
        self._nodes[nid] = ThoughtNode(
            node_id=nid,
            content=content,
            parents=parents or [],
            score=score,
            is_aggregated=is_aggregated,
        )
        return nid

    def get(self, nid: int) -> ThoughtNode:
        return self._nodes[nid]

    def frontier(self, score_threshold: float = 0.3) -> list[ThoughtNode]:
        """Nodes with no children above threshold — candidates for next expansion."""
        has_child = set()
        for node in self._nodes.values():
            for p in node.parents:
                has_child.add(p)
        return [
            n for n in self._nodes.values()
            if n.node_id not in has_child and n.score >= score_threshold
        ]

import anthropic, json

client = anthropic.Anthropic()
MODEL = "claude-sonnet-4-6"

def generate(problem: str, node: ThoughtNode, branching: int = 2) -> list[str]:
    prompt = (
        f"Problem: {problem}

"
        f"Current partial solution:
{node.content}

"
        f"Generate {branching} distinct continuations. "
        f"Return a JSON array of strings."
    )
    r = client.messages.create(
        model=MODEL, max_tokens=1024,
        messages=[{"role": "user", "content": prompt}],
    )
    return json.loads(r.content[0].text)

def score(problem: str, path_so_far: str) -> float:
    prompt = (
        f"Problem: {problem}

Partial solution:
{path_so_far}

"
        f"Rate progress toward a correct solution from 0.0 to 1.0. "
        f"Return only the number."
    )
    r = client.messages.create(
        model=MODEL, max_tokens=16,
        messages=[{"role": "user", "content": prompt}],
    )
    return float(r.content[0].text.strip())

def aggregate(problem: str, node_a: ThoughtNode, node_b: ThoughtNode) -> str:
    """Core GoT operation: merge two independent partial solutions."""
    prompt = (
        f"Problem: {problem}

"
        f"Partial solution A:
{node_a.content}

"
        f"Partial solution B:
{node_b.content}

"
        f"Synthesise the best insights from A and B into a single, "
        f"stronger partial solution. Do not simply concatenate them."
    )
    r = client.messages.create(
        model=MODEL, max_tokens=1024,
        messages=[{"role": "user", "content": prompt}],
    )
    return r.content[0].text

def refine(problem: str, node: ThoughtNode) -> str:
    prompt = (
        f"Problem: {problem}

Draft solution:
{node.content}

"
        f"Improve this draft. Fix errors, fill gaps, sharpen reasoning."
    )
    r = client.messages.create(
        model=MODEL, max_tokens=1024,
        messages=[{"role": "user", "content": prompt}],
    )
    return r.content[0].text

import anthropic

client = anthropic.Anthropic()

def embedding_similarity(text_a: str, text_b: str) -> float:
    """Rough semantic similarity via a short LLM comparison."""
    r = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=8,
        messages=[{
            "role": "user",
            "content": (
                f"Rate semantic similarity 0.0-1.0 (1=identical).
"
                f"Text A: {text_a[:300]}
Text B: {text_b[:300]}
Return only the number."
            ),
        }],
    )
    return float(r.content[0].text.strip())

def should_aggregate(node_a: ThoughtNode, node_b: ThoughtNode,
                     score_min: float = 0.6, diversity_min: float = 0.2) -> bool:
    if node_a.score < score_min or node_b.score < score_min:
        return False
    sim = embedding_similarity(node_a.content, node_b.content)
    # Only aggregate if diverse enough (low similarity = complementary)
    return sim < (1.0 - diversity_min)
